#include "string.h"
#include "bsp_usart.h"

#define VOFA_CH_MAX 32

static USARTInstance *vofa_justfloat_instance;
static float vofa_ch_data[VOFA_CH_MAX];
static uint8_t ch_total_num = 0;

static const uint8_t justfloat_tail[4] = {0x00, 0x00, 0x80, 0x7F};

uint8_t Vofa_JustFloat_Init(uint8_t ch_num)
{
  if (ch_num == 0 || ch_num > VOFA_CH_MAX)
    return 1;

  extern UART_HandleTypeDef huart7;
  USART_Init_Config_s conf = {
    .recv_buff_size = 64,
    .usart_handle = &huart7,
    .module_callback = NULL
};

  vofa_justfloat_instance = USARTRegister(&conf);
  if (!vofa_justfloat_instance)
    return 1;

  memset(vofa_ch_data, 0, sizeof(vofa_ch_data));
  ch_total_num = ch_num;
  return 0;
}

uint8_t Vofa_JustFloat_Send(float data, uint8_t ch)
{
  if (ch >= ch_total_num)
    return 1;

  vofa_ch_data[ch] = data;
  return 0;
}

uint8_t Vofa_JustFloat_loop(void)
{
  if (!vofa_justfloat_instance || ch_total_num == 0)
    return 2;

  uint16_t len = ch_total_num * sizeof(float) + 4;
  uint8_t send_buff[len];

  memcpy(send_buff, vofa_ch_data, ch_total_num * sizeof(float));
  memcpy(&send_buff[ch_total_num * sizeof(float)], justfloat_tail, 4);

  USARTSend(vofa_justfloat_instance,
            send_buff,
            len,
            USART_TRANSFER_BLOCKING);
  return 0;
}

#include "string.h"
#include "bsp_usart.h"

#define VOFA_CH_MAX 32
#define VOFA_MAX_PACKET_SIZE (VOFA_CH_MAX * sizeof(float) + 4)  // 最大包长度 132 字节

static USARTInstance *vofa_justfloat_instance;
static float vofa_ch_data[VOFA_CH_MAX];
static uint8_t ch_total_num = 0;
static uint8_t send_buff_static[VOFA_MAX_PACKET_SIZE];  // 静态缓冲区，避免栈溢出

static const uint8_t justfloat_tail[4] = {0x00, 0x00, 0x80, 0x7F};

uint8_t Vofa_JustFloat_Init(uint8_t ch_num)
{
  if (ch_num == 0 || ch_num > VOFA_CH_MAX)
    return 1;

